SELECT o.*, m.member_email, s.site_nm, cou.coupon_nm, cd_os.code_label AS order_status_cd_nm, cd_pm.code_label AS pay_method_cd_nm, cd_ds.code_label AS dliv_status_cd_nm, cd_ac.code_label AS access_channel_cd_nm, cd_ap.code_label AS appr_status_cd_nm FROM od_order o LEFT JOIN mb_member m ON m.member_id = o.member_id LEFT JOIN sy_site s ON s.site_id = o.site_id LEFT JOIN pm_coupon cou ON cou.coupon_id = o.coupon_id LEFT JOIN sy_code cd_os ON cd_os.code_grp = 'ORDER_STATUS' AND cd_os.code_value = o.order_status_cd LEFT JOIN sy_code cd_pm ON cd_pm.code_grp = 'PAY_METHOD' AND cd_pm.code_value = o.pay_method_cd LEFT JOIN sy_code cd_ds ON cd_ds.code_grp = 'DLIV_STATUS' AND cd_ds.code_value = o.dliv_status_cd LEFT JOIN sy_code cd_ac ON cd_ac.code_grp = 'ACCESS_CHANNEL' AND cd_ac.code_value = o.access_channel_cd LEFT JOIN sy_code cd_ap ON cd_ap.code_grp = 'APPROVAL_STATUS' AND cd_ap.code_value = o.appr_status_cd
ORDER BY o.order_id ASC ORDER BY o.order_id DESC ORDER BY o.member_nm ASC ORDER BY o.member_nm DESC ORDER BY o.order_date ASC ORDER BY o.order_date DESC ORDER BY o.order_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

