ORDER BY o.order_id ASC ORDER BY o.order_id DESC ORDER BY o.member_nm ASC ORDER BY o.member_nm DESC ORDER BY o.order_date ASC ORDER BY o.order_date DESC ORDER BY o.order_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

