UPDATE od_order
order_status_cd = #{orderStatusCd}, order_status_cd_before = #{orderStatusCdBefore}, pay_amt = #{payAmt}, dliv_status_cd = #{dlivStatusCd}, memo = #{memo}, appr_status_cd = #{apprStatusCd}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE order_id = #{orderId}
